import java.io.IOException;

public class SecureCommandExecution {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Usage: java SecureCommandExecution <command>");
            return;
        }

        String userInput = args[0];

        try {
            ProcessBuilder processBuilder = new ProcessBuilder("ping", userInput);
            Process process = processBuilder.start();

            int exitCode = process.waitFor();
            if (exitCode == 0) {
                System.out.println("Command executed successfully.");
            } else {
                System.out.println("Command execution failed.");
            }
        } catch (IOException | InterruptedException e) {
            System.out.println("An error occurred while executing the command.");
        }
    }
}

### Explanation:
취약유형: Command Injection
